mapper.delete:
/* TM_ECS_INTN_ATHR_Dao_deleteAthrMng */
DELETE FROM
	tm_ecs_intn_athr 
WHERE
	ATHR_ID = #{athrId}

mapper.select:
/* TM_ECS_INTN_ATHR_Dao_retrieveAthrGrp */ SELECT INTN_SYS_DIV_CD, SUBSTR(A.ATHR_ID,4,2) AS INTN_BIZN_DIV_CD, ATHR_ID, ATHR_NM, ATHR_DC, IDVINFO_DEAL_YN FROM tm_ecs_intn_athr A WHERE INTN_SYS_DIV_CD = #{intnSysDivCd}
AND ATHR_NM LIKE #{athrNm} || '%'
ORDER BY
, A.ATHR_ID

/* TM_ECS_INTN_ATHR_Dao_retrieveAthrSysDivCd */ SELECT DISTINCT D.CMMN_CD AS SYS_DIV_CD, D.CMMN_CD_NM AS SYS_DIV_CD_NM FROM HRM.vm_hr01601 A, tm_ecs_intn_usr_athr B, tm_ecs_intn_athr C, tc_ecs_cd D WHERE A.EMPNO = B.USR_ID AND B.ATHR_ID = C.ATHR_ID AND C.INTN_SYS_DIV_CD = D.CMMN_CD AND D.CLS_CD = #{sysDivCd}
AND A.EMPNO = #{usrId}
ORDER BY D.CMMN_CD

/* 시스템 구분 조회 */
/* TM_ECS_INTN_ATHR_Dao_retrieveAthrSysDivCd */
SELECT
	B.SYS_DIV_CD,
	C.CMMN_CD_NM AS SYS_DIV_CD_NM
FROM
	HRM.vm_hr01601 A,
	tm_ecs_intn_usr_sys_athr B,
	tc_ecs_cd C
WHERE
	A.EMPNO = B.USR_ID
	AND B.USE_YN = 'Y'
	AND B.SYS_DIV_CD = C.CMMN_CD
	AND C.CLS_CD = #{sysDivCd}

	/* 사번으로 검색 */
	AND B.USR_ID = #{usrId}


	/* 시스템구분코드로 검색 */
	AND C.CMMN_CD = #{cmmnCd}

ORDER BY
	C.SORT_ORDR
